<?php
 declare(strict_types=1); namespace tapmeppe\composer\blueprint; class Request { private array $arguments = []; function __construct() { global $argv; array_shift($argv); foreach ($argv as $i => $argument) { $argument = explode('=', $argument, 2); if (isset($argument[1])) $this->arguments[$argument[0]] = $argument[1]; else $this->arguments[$i] = $argument[0]; } } function getArgument(string $key, mixed $fallback = null): mixed { return $this->arguments[$key] ?? $fallback; } function getArguments(): object { return (object) $this->arguments; } function updateArguments(array $arguments): void { $this->arguments = $arguments; } } 